!function($){
  "use strict";

  var $win = $(window),
      $doc = $(document),
      $body = $("body"),
      $html = $("html"),
      T4S = T4SThemeSP;

  // Section Events: عند تحميل أي سكشن
  $doc.on("shopify:section:load", function(e){
    var sectionId = e.detail.sectionId,
        $section = $("#shopify-section-" + sectionId);

    // Flickity Slider
    if($section.find(".flickityt4s").length > 0){
      $section.find(".flickityt4s").each(function(i){
        this["flickityt4s" + i] = new T4S.Carousel(this);
      });
    }

    // Tabs
    if($section.hasClass("t4s_tp_tab") || $section.hasClass("t4s_tp_tab2") || $section.hasClass("t4s_tp_tab3")){
      T4S.Tabs.Default();
      T4S.Tabs.Accordion();
    }

    if($section.hasClass("t4s_tp_tab_simple")){
      T4S.Tabs.Simple();
    }

    // Popup
    T4S.PopupMFP();

    // Product Init (Quick View / Quick Shop)
    if($section.find("[data-product-featured]:not(.initProducts__enabled)").length){
      var $products = $section.find("[data-product-featured]:not(.initProducts__enabled)");
      $products.addClass("initProducts__enabled");
      new T4S.Product($products);
    }

    // Video
    if($section.hasClass("t4s_tp_video")){
      T4S.Video.initPoster();
      T4S.PopupMFP();
    }

    // Countdown
    if($section.hasClass("t4s_tp_cd")){
      T4S.Countdown();
    }

    // Isotope (Gallery Layout)
    if($section.hasClass("t4s_tp_istop")){
      var $iso = $section.find(".isotope__t4s");
      if($iso.length > 0){
        T4S.Isotopet4s.init($iso);
        setTimeout(function(){
          $iso.isotopet4s("layout");
        }, 44);
        T4SThemeSP.Isotopet4s.filter();
      }
    }

    // Parallax Background
    if($section.hasClass("t4s_tp_parallax")){
      T4S.ParallaxInt();
      $(".t4s-parallax-bg:not(.lazyloadt4sed)").one("lazyloaded", function(){
        setTimeout(function(){
          T4S.ParallaxInt();
        }, 100);
      });
    }

    // Sticky Header
    if(sectionId === "top-bar"){
      $html.removeClass("is-header--stuck");
      T4S.Header.stickyInit();
    }

    // Drawer أو عناصر تفاعلية
    if($section.hasClass("t4s-section-sidebar")){
      T4S.Drawer.close();
    }
  });

}(jQuery_T4NT);
